<script>
export default {
  name: "OptionsAccesories",
  methods: {
    deleteClass() {
      let c = document.getElementById('accesories').children, i;
      for (i = 0; i < c.length; i++) {
        c[i].classList.remove('show');
      }
    },
    showEarphones() {
      this.deleteClass();
      document.querySelector('#a_earphones').classList.add('show');
    },
    showEarring1() {
      this.deleteClass();
      document.querySelector('#a_earring1').classList.add('show');
    },
    showEarring2() {
      this.deleteClass();
      document.querySelector('#a_earring2').classList.add('show');
    },
    showEarring3() {
      this.deleteClass();
      document.querySelector('#a_earring3').classList.add('show');
    },
    showGolden() {
      this.deleteClass();
      document.querySelector('#a_golden').classList.add('show');
    },
    showUkrainian() {
      this.deleteClass();
      document.querySelector('#a_ukrainian').classList.add('show');
    }
  }
}
</script>
